def _minimal_metadata() -> str:
    cert_x509 = _pem_cert_to_x509(IDP_CFG["certificate_pem"])
    nsmap = {
        None: "urn:oasis:names:tc:SAML:2.0:metadata",
        "ds": "http://www.w3.org/2000/09/xmldsig#",
    }
    ed = etree.Element(
        "EntityDescriptor",
        nsmap=nsmap,
        entityID=IDP_CFG["entity_id"],
    )
    idpsso = etree.SubElement(ed, "IDPSSODescriptor", protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol")
    keydesc = etree.SubElement(idpsso, "KeyDescriptor", use="signing")
    keyinfo = etree.SubElement(keydesc, etree.QName(nsmap["ds"], "KeyInfo"))
    x509data = etree.SubElement(keyinfo, etree.QName(nsmap["ds"], "X509Data"))
    x509cert = etree.SubElement(x509data, etree.QName(nsmap["ds"], "X509Certificate"))
    x509cert.text = cert_x509

    sso = etree.SubElement(
        idpsso,
        "SingleSignOnService",
        Binding=DEFAULT_BINDING,
        Location=IDP_CFG["sso_url"],
    )
    nameidfmt = etree.SubElement(idpsso, "NameIDFormat")
    nameidfmt.text = IDP_CFG["nameid_format"]

    xml = etree.tostring(ed, xml_declaration=True, encoding="UTF-8", pretty_print=True).decode("utf-8")
    return xml


