LOGIN_TEMPLATE = """<!doctype html>
<html>
  <head><meta charset="utf-8"/><title>Internal IdP Login</title></head>
  <body>
    <h2>Internal IdP Login</h2>
    {% if error %}<p style="color:red">{{ error }}</p>{% endif %}
    <form method="post" action="/login">
      <input type="hidden" name="acs" value="{{ acs }}"/>
      <input type="hidden" name="audience" value="{{ audience }}"/>
      <input type="hidden" name="in_response_to" value="{{ in_response_to }}"/>
      <input type="hidden" name="relay_state" value="{{ relay_state }}"/>
      <label>Email: <input name="email" type="email" required value="{{ email or '' }}"/></label><br/><br/>
      <label>Password: <input name="password" type="password" required/></label><br/><br/>
      <button type="submit">Sign in</button>
    </form>
  </body>
</html>"""


def _validate_acs(acs_url: str):
    if not _safe_url(acs_url):
        raise ValueError("ACS URL must be https://")
    allowed = IDP_CFG["allowed_acs_urls"]
    if allowed and acs_url not in allowed:
        raise PermissionError("ACS URL not allowed by policy")


def _authenticate_user(email: str, password: str) -> bool:
    demo_user = os.environ.get("IDP_DEMO_USER", "user@example.com")
    demo_pass = os.environ.get("IDP_DEMO_PASS", "password")
    return email.lower() == demo_user.lower() and password == demo_pass


@app.get("/sso")
def sso():
    acs = request.args.get("acs", "").strip()
    audience = request.args.get("audience", "").strip() or IDP_CFG["audience_default"]
    in_response_to = request.args.get("request_id", "").strip() or None
    relay_state = request.args.get("RelayState", "").strip() or ""

    if not acs:
        return {"error": "Missing acs query param"}, 400
    try:
        _validate_acs(acs)
    except Exception as e:
        return {"error": str(e)}, 400

    if not audience:
        return {"error": "Missing audience (provide ?audience=... or set IDP_AUDIENCE_DEFAULT)"}, 400

    return render_template_string(
        LOGIN_TEMPLATE,
        error=None,
        acs=acs,
        audience=audience,
        in_response_to=in_response_to or "",
        relay_state=relay_state,
        email="",
    )


@app.post("/login")
def login():
    acs = (request.form.get("acs") or "").strip()
    audience = (request.form.get("audience") or "").strip() or IDP_CFG["audience_default"]
    in_response_to = (request.form.get("in_response_to") or "").strip() or None
    relay_state = request.form.get("relay_state")
    if relay_state is not None:
        relay_state = relay_state.strip()
    email = (request.form.get("email") or "").strip()
    password = request.form.get("password") or ""

    if not acs:
        return {"error": "Missing acs"}, 400
    try:
        _validate_acs(acs)
    except Exception as e:
        return {"error": str(e)}, 400

    if not audience:
        return {"error": "Missing audience"}, 400

    if not email or not password:
        return render_template_string(
            LOGIN_TEMPLATE,
            error="Missing credentials",
            acs=acs,
            audience=audience,
            in_response_to=in_response_to or "",
            relay_state=relay_state or "",
            email=email,
        ), 400

    if not _authenticate_user(email, password):
        return render_template_string(
            LOGIN_TEMPLATE,
            error="Invalid credentials",
            acs=acs,
            audience=audience,
            in_response_to=in_response_to or "",
            relay_state=relay_state or "",
            email=email,
        ), 401

    attrs = {
        "email": email,
        "uid": email.split("@")[0],
        "groups": (os.environ.get("IDP_DEMO_GROUPS", "users").split(",")),
    }

    xml = _build_response_xml(
        in_response_to=in_response_to,
        destination=acs,
        issuer=IDP_CFG["entity_id"],
        acs_url=acs,
        audience=audience,
        nameid=email,
        nameid_format=IDP_CFG["nameid_format"],
        attributes=attrs,
    )

    saml_response_b64 = _b64e(xml.encode("utf-8"))
    html = _render_post_form(acs, saml_response_b64, relay_state if relay_state else None)
    resp = make_response(html, 200)
    resp.headers["Content-Type"] = "text/html; charset=utf-8"
    resp.headers["Cache-Control"] = "no-store"
    resp.headers["Pragma"] = "no-cache"
    return resp


