    host = os.environ.get("IDP_HOST", "0.0.0.0")
    port = int(os.environ.get("IDP_PORT", "8443"))
    certfile = os.environ.get("IDP_TLS_CERTFILE", "").strip()
    keyfile = os.environ.get("IDP_TLS_KEYFILE", "").strip()

    if not certfile or not keyfile:
        raise RuntimeError("Set IDP_TLS_CERTFILE and IDP_TLS_KEYFILE for HTTPS serving.")

    logger.info("Starting %s on https://%s:%d", APP_NAME, host, port)
    app.run(host=host, port=port, ssl_context=(certfile, keyfile), threaded=True)